// ── CONFIGURATION — edit the values below ─────────────────────────
const ORBIT_API_URL    = 'https://prod.nesecurity.com.br/orbit-core'; // TODO
const ORBIT_BASIC_USER = 'orbitadmin';                               // TODO
const ORBIT_BASIC_PASS = '';   // leave empty if using ORBIT_API_KEY  // TODO
const ORBIT_API_KEY    = '';   // use instead of BasicAuth if preferred
// ────────────────────────────────────────────────────────────────────

const exec   = ($input.item.json.execution) || {};
const wfInfo = ($input.item.json.workflow)   || {};
const err    = exec.error || {};
const wfName = wfInfo.name || wfInfo.id || 'unknown';
const wfId   = wfInfo.id  || '';
const execId = String(exec.id || 'unknown');
const node   = (typeof err.node === 'object' ? err.node?.name : err.node) || exec.lastNodeExecuted || 'unknown';
const errMsg = err.message || 'Execution failed';
const now    = new Date().toISOString();

const event = {
  ts:          now,
  asset_id:    `workflow:${wfName}`,
  namespace:   'n8n',
  kind:        'execution_error',
  severity:    'high',
  title:       `Workflow "${wfName}" failed — ${errMsg.slice(0, 100)}`,
  message:     `Execution ${execId} failed. Last node: ${node}. Error: ${errMsg}`,
  fingerprint: `n8n:error:${execId}`,
  attributes: {
    execution_id:       execId,
    execution_url:      exec.url || '',
    workflow_id:        wfId,
    workflow_name:      wfName,
    last_node_executed: exec.lastNodeExecuted || '',
    error_message:      errMsg,
    error_node:         node,
    mode:               exec.mode || '',
  },
};

// Build Authorization header
let authHeader;
if (ORBIT_API_KEY) {
  authHeader = `Bearer ${ORBIT_API_KEY}`;
} else {
  const b64 = Buffer.from(`${ORBIT_BASIC_USER}:${ORBIT_BASIC_PASS}`).toString('base64');
  authHeader = `Basic ${b64}`;
}

return {
  orbitUrl:   `${ORBIT_API_URL}/api/v1/ingest/events`,
  authHeader: authHeader,
  body:       JSON.stringify({ events: [event] }),
};
